CREATE OR REPLACE FUNCTION log_player_name_changes() 
RETURNS trigger AS 
$BODY$
BEGIN 
    IF NEW.player_name <> OLD.player_name THEN 
        INSERT INTO player_audits(player_id, old_player_name, changed_on) 
        VALUES(OLD.player_api_id, OLD.player_name, now()); 
    END IF; 
    RETURN NEW; 
END; 
$BODY$
LANGUAGE plpgsql;

CREATE TRIGGER tr_change_playername 
AFTER UPDATE OF player_name ON player 
FOR EACH ROW 
EXECUTE PROCEDURE log_player_name_changes()

CREATE OR REPLACE FUNCTION what_quarter_is(date_in DATE, start_month INTEGER)
RETURNS INTEGER AS $$
DECLARE
    month_offset INTEGER;
    adjusted_month INTEGER;
BEGIN
    -- Calculate the offset from the start month
    month_offset := (EXTRACT(MONTH FROM date_in)::INTEGER - start_month + 12) % 12;

    -- Adjust month to be 1-12 relative to start_month
    adjusted_month := month_offset + 1;

    -- Calculate which quarter (1-4) the adjusted month falls into
    RETURN CEIL(adjusted_month::DECIMAL / 3.0)::INTEGER;
END;
$$ LANGUAGE plpgsql;

-- Example usage:
-- SELECT what_quarter_is('1995-07-23', 4); -- Returns 2
-- SELECT what_quarter_is('1995-04-15', 4); -- Returns 1 (April is first month of Q1)
-- SELECT what_quarter_is('1995-06-30', 4); -- Returns 1 (June is third month of Q1)
-- SELECT what_quarter_is('1995-07-01', 4); -- Returns 2 (July is first month of Q2)

