CREATE OR REPLACE FUNCTION pg_try_advisory_lock_with_timeout(key bigint)
RETURNS boolean AS $$
DECLARE
    lock_acquired boolean;
    start_time timestamp;
    elapsed interval;
BEGIN
    start_time := clock_timestamp();

    LOOP
        -- Try to acquire the lock
        SELECT pg_try_advisory_lock(key) INTO lock_acquired;

        -- If lock was acquired, return true
        IF lock_acquired THEN
            RETURN true;
        END IF;

        -- Check if timeout (1 second) has been reached
        elapsed := clock_timestamp() - start_time;
        IF elapsed >= interval '1 second' THEN
            RETURN false;
        END IF;

        -- Brief pause before retrying
        PERFORM pg_sleep(0.01);
    END LOOP;
END;
$$ LANGUAGE plpgsql

